INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES (' ESPRO', 'Projeto do Gestores do Futuro planejou um dia de brincadeiras para as crianças. Laços da Esperança tem como missão promover acolhimento, educação e alegria para crianças vulneráveis, oferecendo oportunidades de desenvolvimento integral e construindo vínculos transformadores com dignidade e afeto', '2025-11-12T08:00:00:00Z', '2025-11-12T08:00:00:00Z', 'interno', true, '[]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('Sorriso é Coisa Séria', 'Na atividade proposta, crianças da instituição ANA - Santana, de 06 a 10 anos, participarão de atividades lúdico educativas de saúde bucal realizadas pela equipe de dentistas do Sesc Campinas, com orientações sobre cuidados e higiene e distribuição de kits de saúde bucal. A ação será complementada pela intervenção "O Mundo em Minha Boca", na qual o grupo propõe um resgate poético e musical sobre as funções da boca como meio de experimentação do mundo e forma de expressão. O espetáculo é interativo e integrado com uma oficina de origami.', '2025-11-06T08:30:00:00Z', '2025-11-06T08:30:00:00Z', 'interno', true, '[]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
