INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('CAFÉ DA MANHÃ COM FAMILIAS ', 'NO DIA 21/02/2026 TEREMOS NOSSO CAFÉ COM FAMILIAS, ONDE TEREMOS A PRESENÇA DA SECRETARIA DA ASSISTENCIA SOCIAL - VANDERCLÉIA MORO. SERÁ UM ENCONTRO INFORMATIVO, ONDE AS FAMILIAS RECEBERÃO INFORMAÇÕES SOBRE NOSSO SERVIÇO, E TAMBÉM SOBRE SERVIÇOS, QUE HOJE ESTÃO DISPONIVEIS PARA A COMUNIDADE. SERÁ DIVULGADO NESTE DIA, O PRIMEIRO VARAL SOLIDARIO DO ANA DIC, EM PARCERIA COM A SECRETARIA DA ASSISTENCIA. ', '2026-02-21T09:00:00:00Z', '2026-02-21T09:00:00:00Z', 'público', true, '[]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('VARAL SOLIDÁRIO', 'O Varal Solidário, na Unidade Nilópolis, em parceria com o Programa Próximo Passo. Será uma manhã especial de cuidado, orientação e apoio às famílias da comunidade.', '2026-02-28T09:00:00:00Z', '2026-02-28T09:00:00:00Z', 'interno', true, '["https://drive.google.com/open?id=1-m9VnH0TX2icrsTFf-iG6nLUt7BFVgXq"]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('ENCONTRO DE FAMILIA', 'Um momento para apresentar nossas atividades , explicar nosso serviço de apoio com  Serviço Social e Psicologia, e  se encantar com o talento das crianças nas apresentações.', '2026-03-07T09:00:00:00Z', '2026-03-07T09:00:00:00Z', 'interno', true, '[]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('Encontro de Famílias', 'Os Encontros de Família são fundamentais para o nosso trabalho e tem como principal objetivo promover o fortalecimento de vínculos entres as crianças e adolescentes e seus familiares. Isso ocorre a partir de apresentações das atividades que realizaram ao longo do bimestre, bem como a partir de atividades interativas com as família e palestras cuja temática é escolhida de acordo com a necessidade identificada no dia a dia do acompanhamento com as famílias.', '2026-03-21T08:00:00:00Z', '2026-03-21T08:00:00:00Z', 'interno', true, '[]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('VARAL SOLIDÁRIO ', 'Evento realizado pela Prefeitura de Camppinas - Secretaria da Assistencia Social, durante o evento teremos - doações de roupas, atualização do cadastro unico, orientações auxilios sociais, vagas de empregos, cursos / captações, orientação MEI, exame de vista, corte de cabelo, aula de pilates. ', '2026-03-21T08:00:00:00Z', '2026-03-21T08:00:00:00Z', 'público', true, '[]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('Teatro de Páscoa', 'O teatro é comemorativo, por ocasião da Páscoa, a peça será apresentada pelo Grupo Ecco, um grupo voluntário cristão. O evento ocorrerá de manhã e a tarde no mesmo dia, na quadra da unidade Nilópolis, com participação das crianças da unidade Santana.', '2026-03-30T08:00:00:00Z', '2026-03-30T08:00:00:00Z', 'interno', true, '["https://drive.google.com/open?id=1SxEwT2RqMW6QTdqBMJL0Ctj59sQzptD2"]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
