INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('Roda de Conversa (Saúde Emocional)', 'A roda de conversa sobre saúde emocional, sera realizada com os idosos e conduzida por psicopedagoga voluntária, proporcionando um momento de acolhimento, escuta e troca de experiências. A atividade vai contribuir para o fortalecimento de vínculos, promoção do bem-estar e prevenção do isolamento social, alinhando-se aos objetivos do SCFV.', '2023-03-31T11:00:00:00Z', '2023-03-31T11:00:00:00Z', 'interno', true, '[]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('Visita Empresa Brasiliense', 'A visita à empresa Brasiliense, que será realizada com os adolescentes do projeto Trilhando Futuro, tem como objetivo proporcionar conhecimento sobre o ambiente profissional e aproximá-los do mundo do trabalho. Durante a atividade, os participantes irão conhecer a empresa e participar de palestras orientativas, contribuindo para o desenvolvimento de habilidades, ampliação de perspectivas e preparação para futuras oportunidades profissionais.', '2026-03-30T09:00:00:00Z', '2026-03-30T09:00:00:00Z', 'público', true, '[]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('Ação Social - Objetivo ', 'O colégio Objetivo irá realizar uma ação social, em unidade Dic, por comemoração a Pascoa, onde estará entregando 1 caixa de bombom para cada atendido. Durante o periodo estaremos com atividades socieducativas e recreação. ', '2026-04-02T13:30:00:00Z', '2026-04-02T13:30:00:00Z', 'público', true, '[]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('Páscoa - JNI', 'Local e Público-Alvo: O evento foca nas crianças das comunidades do bairro Gênesis e do ANA Nilópolis (unidade da Associação Nazarena Assistencial no Jardim Nilópolis). A celebração ocorre no Ginásio Municipal Dep. Nabi Abi Chedid, localizado no Parque Anhumas (Rua Ipê da Várzea).
INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('Exposição Carbono Zero', 'O Projeto Futuro Carbono Zero percorre o estado levando arte, tecnologia e reflexões sobre o planeta em uma carreta transformada em alegria. A amostra cria um percurso sensorial que une criatividade e educação ambiental.
