INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('Encontro de Profissões', 'O Encontro de Profissões Objetivo é um evento gratuito que conecta estudantes do ensino médio com profissionais renomados de diversas áreas. Uma manhã dedicada a esclarecer dúvidas, apresentar possibilidades e inspirar o seu futuro profissional.', '2026-05-09T08:30:00:00Z', '2026-05-09T08:30:00:00Z', 'público', true, '[]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('Encontro de mulheres - Mulheres que florescem ', 'Maio é trabalhado a semana da familia, normalmente não comemoramos o "Dia das mães" e sim semana da familia. Mas esse ano, gostariamos de reunir mulheres que cuidam. Assim oferecermos um tempo de qualidade, com uma proposta dinamica e acolhedora. O encontro “Mulheres que Florescem” surge como uma proposta de acolhimento, fortalecimento e renovação. Assim como uma flor precisa de tempo, cuidado e condições adequadas para florescer, cada mulher também passa por processos necessários para alcançar seu potencial. Este evento busca proporcionar um ambiente seguro onde mulheres possam se reconectar consigo mesmas, fortalecer sua identidade e compreender que mesmo em meio às dificuldades, é possível florescer.
INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('Baile da Pessoa Idosa', 'O Baile da Pessoa Idosa, realizado pelo CMI, tem como proposta promover a integração, socialização e valorização das pessoas idosas, proporcionando um momento de lazer, convivência e fortalecimento de vínculos.', '2026-04-30T14:00:00:00Z', '2026-04-30T14:00:00:00Z', 'público', true, '[]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');
