INSERT INTO public.events (title, description, start_datetime, end_datetime, visibility, marketing_request, attachments, created_by, status, unit, event_type) VALUES ('Ação 18  Maio', 'O 18 de Maio é o Dia Nacional de Combate ao Abuso e à Exploração Sexual de Crianças e Adolescentes no Brasil, marco da campanha #FaçaBonito. A data visa mobilizar a sociedade para proteger menores, denunciar abusos e quebrar o ciclo de violência, com o Disque 100 como principal ferramenta de denúncia', '2026-05-23T08:00:00:00Z', '2026-05-23T08:00:00:00Z', 'público', true, '[]', 'mkt@anabrasil.org', 'confirmado', 'Evento Geral do Grupo', 'outro');